describe('test dirty', function() {
    let tempDir;
    let tempFile;

    beforeEach(function() {
        tempDir = fs.mkdtempSync(path.join(os.tmpdir(), 'dirty-test-'));
        tempFile = path.join(tempDir, 'test.db');
    });

    afterEach(function() {
        if (fs.existsSync(tempFile)) {
            fs.unlinkSync(tempFile);
        }
        fs.rmdirSync(tempDir);
    });

    it('should create in-memory database when no path provided', function(done) {
        const db = new dirty.Dirty();

        db.on('load', (count) => {
            assert.strictEqual(count, 0);
            assert.strictEqual(db.size(), 0);
            done();
        });
    });

    it('should set and get values in memory', function(done) {
        const db = new dirty.Dirty();

        db.on('load', () => {
            db.set('key1', 'value1');
            db.set('key2', { nested: 'object' });

            assert.strictEqual(db.get('key1'), 'value1');
            assert.deepStrictEqual(db.get('key2'), { nested: 'object' });
            assert.strictEqual(db.size(), 2);
            done();
        });
    });

    it('should remove values using rm method', function(done) {
        const db = new dirty.Dirty();

        db.on('load', () => {
            db.set('key1', 'value1');
            db.set('key2', 'value2');
            assert.strictEqual(db.size(), 2);

            db.rm('key1');
            assert.strictEqual(db.get('key1'), undefined);
            assert.strictEqual(db.size(), 1);
            done();
        });
    });

    it('should update values using update method', function(done) {
        const db = new dirty.Dirty();

        db.on('load', () => {
            db.set('counter', 5);

            db.update('counter', (val) => val + 1);
            assert.strictEqual(db.get('counter'), 6);

            db.update('newkey', (val) => (val || 0) + 10);
            assert.strictEqual(db.get('newkey'), 10);
            done();
        });
    });

    it('should iterate over keys with forEach', function(done) {
        const db = new dirty.Dirty();

        db.on('load', () => {
            db.set('a', 1);
            db.set('b', 2);
            db.set('c', 3);

            const collected = [];
            db.forEach((key, val) => {
                collected.push([key, val]);
            });

            assert.strictEqual(collected.length, 3);
            assert.deepStrictEqual(collected.sort(), [['a', 1], ['b', 2], ['c', 3]]);
            done();
        });
    });

    it('should break forEach when callback returns false', function(done) {
        const db = new dirty.Dirty();

        db.on('load', () => {
            db.set('a', 1);
            db.set('b', 2);
            db.set('c', 3);

            const collected = [];
            db.forEach((key, val) => {
                collected.push([key, val]);
                return collected.length < 2; // Stop after 2 items
            });

            assert.strictEqual(collected.length, 2);
            done();
        });
    });

    it('should persist data to file', function(done) {
        const db = new dirty.Dirty(tempFile);

        db.on('load', () => {
            db.set('persistent', 'data', (err) => {
                assert.strictEqual(err, undefined);

                // Verify file was written
                const content = fs.readFileSync(tempFile, 'utf-8');
                assert(content.includes('persistent'));
                assert(content.includes('data'));
                done();
            });
        });
    });

    it('should load existing data from file', function(done) {
        // First, create a file with some data
        const testData = '{"key":"test","val":"value"}\n{"key":"num","val":42}\n';
        fs.writeFileSync(tempFile, testData);

        const db = new dirty.Dirty(tempFile);

        db.on('load', (count) => {
            assert.strictEqual(count, 2);
            assert.strictEqual(db.get('test'), 'value');
            assert.strictEqual(db.get('num'), 42);
            done();
        });
    });

    it('should handle file not found gracefully', function(done) {
        const nonExistentFile = path.join(tempDir, 'does-not-exist.db');
        const db = new dirty.Dirty(nonExistentFile);

        db.on('load', (count) => {
            assert.strictEqual(count, 0);
            assert.strictEqual(db.size(), 0);
            done();
        });
